class Solution {
    public boolean[] canMakePalindromeQueries(String s, int[][] queries) {
        int n = s.length();
        int[] count = new int[26];
        for (int i = 0; i < n / 2; i++) {
            count[s.charAt(i) - 'a']++;
            count[s.charAt(n - 1 - i) - 'a']--;
        }
        for (int i = 0; i < 26; i++) {
            if (count[i] != 0) {
                count[i] = 1;
            }
        }
        boolean[] prefix = new boolean[26];
        for (int i = 0; i < 26; i++) {
            prefix[i] = count[i] != 0;
        }
        for (int i = 1; i < 26; i++) {
            prefix[i] = prefix[i] || prefix[i - 1];
        }
        boolean[] answer = new boolean[queries.length];
        for (int i = 0; i < queries.length; i++) {
            int a = queries[i][0], b = queries[i][1], c = queries[i][2], d = queries[i][3];
            int diff = (b - a + 1) + (d - c + 1);
            if (diff % 2 == 1) {
                answer[i] = false;
            } else {
                int leftOdd = 0;
                for (int j = a; j <= b; j++) {
                    if (count[s.charAt(j) - 'a'] != 0) {
                        leftOdd++;
                    }
                }
                int rightOdd = 0;
                for (int j = c; j <= d; j++) {
                    if (count[s.charAt(j) - 'a'] != 0) {
                        rightOdd++;
                    }
                }
                if (leftOdd % 2 == 1 && rightOdd % 2 == 1) {
                    answer[i] = prefix[Math.min(leftOdd, rightOdd) - 1];
                } else {
                    answer[i] = true;
                }
            }
        }
        return answer;
    }
}
